import React, { useState } from 'react';
import { Shield, Zap, Globe, Check, Lock, ChevronRight, Server, Sparkles, CreditCard, Loader2, RefreshCw, ArrowLeft, Search, Filter, Star, ExternalLink, TrendingUp, ArrowRight, Plus, AlertCircle, ClipboardList } from 'lucide-react';
import { AnalysisResult, CategoryScore, Recommendation } from '../types';

interface DirectoryProps {
  onBack: () => void;
  onViewEntity: (result: AnalysisResult) => void;
  onNavigateToPlan: () => void;
  user: { name: string; email: string; plan: 'free' | 'pro' | 'enterprise'; credits: number } | null;
  directClientCount: number;
  maxClients: number;
}

// Données simulées pour l'annuaire public
const DIRECTORY_DATA = [
  { id: 1, name: 'Stripe', sector: 'Fintech', aeoScore: 98, status: 'Elite', verified: true, desc: "Infrastructure de paiement pour internet." },
  { id: 2, name: 'Linear', sector: 'SaaS B2B', aeoScore: 94, status: 'Elite', verified: true, desc: "Outil de gestion de projet moderne." },
  { id: 3, name: 'Algolia', sector: 'Search API', aeoScore: 89, status: 'Premium', verified: true, desc: "API de recherche rapide et pertinente." },
  { id: 4, name: 'Qonto', sector: 'Banque', aeoScore: 88, status: 'Premium', verified: true, desc: "La néobanque des PME et indépendants." },
  { id: 5, name: 'Doctolib', sector: 'Santé', aeoScore: 85, status: 'Premium', verified: true, desc: "Plateforme de prise de rendez-vous médicaux." },
  { id: 6, name: 'Alan', sector: 'Assurance', aeoScore: 92, status: 'Elite', verified: true, desc: "L'assurance santé simple et transparente." },
  { id: 7, name: 'Swile', sector: 'RH', aeoScore: 78, status: 'Standard', verified: true, desc: "La carte titre-restaurant nouvelle génération." },
  { id: 8, name: 'Payfit', sector: 'RH Tech', aeoScore: 81, status: 'Premium', verified: true, desc: "Gestion de la paie simplifiée." },
];

const Directory: React.FC<DirectoryProps> = ({ onBack, onViewEntity, onNavigateToPlan, user, directClientCount, maxClients }) => {
  const [viewMode, setViewMode] = useState<'browse' | 'join'>('browse');
  const [step, setStep] = useState<'intro' | 'form' | 'payment' | 'success'>('intro');
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedFilter, setSelectedFilter] = useState('All');
  const [showLimitAlert, setShowLimitAlert] = useState(false);

  const isAtLimit = directClientCount >= maxClients && user?.plan !== 'enterprise';
  const planLabel = user?.plan === 'free' ? 'Starter' : user?.plan === 'pro' ? 'Pro' : 'Agency';

  const handleJoinIndex = () => {
    if (isAtLimit) {
      setShowLimitAlert(true);
      return;
    }
    onNavigateToPlan();
  };

  const [formData, setFormData] = useState({
    companyName: '',
    website: '',
    description: '',
    industry: '',
    competitors: ''
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStep('payment');
  };

  const handlePayment = async () => {
    setIsProcessing(true);
    await new Promise(resolve => setTimeout(resolve, 3000));
    setIsProcessing(false);
    setStep('success');
  };

  const filteredDirectory = DIRECTORY_DATA.filter(item => {
    const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase()) || item.desc.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = selectedFilter === 'All' || item.sector === selectedFilter;
    return matchesSearch && matchesFilter;
  });

  const uniqueSectors = ['All', ...Array.from(new Set(DIRECTORY_DATA.map(item => item.sector)))];

  // --- GENERATE MOCK ANALYSIS BASED ON DIRECTORY ITEM ---
  const generateMockAnalysis = (item: typeof DIRECTORY_DATA[0]): AnalysisResult => {
    const url = `https://www.${item.name.toLowerCase()}.com`;
    const score = item.aeoScore;

    // Simulate high scores for Elite items
    const isElite = score > 90;

    const categories: Record<string, CategoryScore> = {
        technical: {
            name: "Infrastructure Technique",
            score: isElite ? 95 : 85,
            weight: 10,
            items: [{ status: 'success', message: 'Temps de réponse TTFB < 100ms' }, { status: 'success', message: 'Rendu SSR optimisé' }]
        },
        entity: {
            name: "Autorité Entité",
            score: score,
            weight: 10,
            items: [
                { status: 'success', message: 'Fiche Knowledge Graph détectée' },
                { status: isElite ? 'success' : 'warning', message: isElite ? 'Page "À propos" détaillée' : 'Page "À propos" perfectible' }
            ]
        },
        semantic: {
            name: "Structure Sémantique",
            score: score - 5,
            weight: 10,
            items: [
                { status: 'success', message: 'Balisage Schema.org Organization valide' },
                { status: 'success', message: 'Structure Hn logique' }
            ]
        },
        content: {
            name: "Profondeur Contenu",
            score: score - 2,
            weight: 10,
            items: [{ status: 'success', message: 'Densité entités nommées élevée' }]
        }
    };

    return {
        url,
        timestamp: new Date().toISOString(),
        globalScore: score,
        categories,
        recommendations: [], // Pas de recommendations en vue publique
        aiCitation: {
            before: `Je n'ai pas d'informations précises sur ${item.name}.`,
            after: `D'après ses données structurées, ${item.name} est un leader en ${item.sector}.`,
            probability: Math.max(score - 10, 50)
        }
    };
  };

  const handleViewDetails = (item: typeof DIRECTORY_DATA[0]) => {
      const mockResult = generateMockAnalysis(item);
      onViewEntity(mockResult);
  };

  // --- COMPOSANT : VUE NAVIGATEUR (Inspiré AI Peekaboo) ---
  const renderBrowser = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
        <div className="text-center space-y-4 mb-12">
            <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">
              Annuaire <span className="text-purple-400 italic">Knowledge Graph</span>
            </h1>
            <p className="text-gray-500 text-lg max-w-2xl mx-auto">
              Explorez les entités certifiées AEO. Ces entreprises ont structuré leurs données pour être citées en priorité par ChatGPT, Claude et Gemini.
            </p>
            <div className="flex justify-center gap-4 pt-4 items-center">
                {user && user.plan !== 'enterprise' && (
                  <div className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-white/[0.03] border border-white/[0.06] rounded-xl">
                    <span className="text-[11px] text-gray-500">Quota projets</span>
                    <span className={`text-sm font-bold ${isAtLimit ? 'text-red-400' : 'text-white'}`}>
                      {directClientCount}/{maxClients}
                    </span>
                  </div>
                )}
                <button
                    onClick={handleJoinIndex}
                    className={`px-6 py-3 font-bold rounded-2xl transition-all flex items-center gap-2 transform hover:scale-105 ${
                      isAtLimit
                        ? 'bg-white/[0.06] border border-white/[0.08] text-gray-400 shadow-none'
                        : 'bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white shadow-lg shadow-purple-500/20'
                    }`}
                >
                    <Sparkles size={18} /> Rejoindre l'Index
                    {isAtLimit && <span className="text-[10px] ml-1 text-red-400">Limite</span>}
                </button>
            </div>
        </div>

        {/* Search & Filters */}
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white/[0.04] p-4 rounded-2xl border border-white/[0.08]">
            <div className="relative w-full md:w-96">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                    type="text" 
                    placeholder="Rechercher une entité..." 
                    className="w-full bg-black/40 border border-white/[0.08] rounded-2xl pl-10 pr-4 py-2.5 text-white focus:border-purple-500/50 outline-none"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>
            <div className="flex gap-2 overflow-x-auto w-full md:w-auto no-scrollbar pb-2 md:pb-0">
                {uniqueSectors.map(sector => (
                    <button
                        key={sector}
                        onClick={() => setSelectedFilter(sector)}
                        className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${selectedFilter === sector ? 'bg-white/20 text-white' : 'bg-transparent text-gray-500 hover:bg-purple-500/10'}`}
                    >
                        {sector}
                    </button>
                ))}
            </div>
        </div>

        {/* Grid des Entités */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">

            {/* Upsell Card - NOW FIRST */}
            <div
              className={`border border-dashed rounded-2xl p-6 flex flex-col items-center justify-center text-center transition-colors cursor-pointer group ${
                isAtLimit ? 'border-red-500/20 hover:bg-red-500/[0.02]' : 'border-white/20 hover:bg-white/[0.04]'
              }`}
              onClick={handleJoinIndex}
            >
                <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform ${
                  isAtLimit ? 'bg-red-500/[0.06]' : 'bg-white/[0.04]'
                }`}>
                    {isAtLimit
                      ? <Lock size={28} className="text-red-400/60" />
                      : <Plus size={32} className="text-gray-500 group-hover:text-white" />
                    }
                </div>
                <h3 className="font-bold text-white mb-1">
                  {isAtLimit ? 'Limite atteinte' : 'Votre entreprise ici ?'}
                </h3>
                <p className="text-sm text-gray-500 mb-4">
                  {isAtLimit
                    ? `Votre plan ${planLabel} est limité à ${maxClients} projet${maxClients > 1 ? 's' : ''}.`
                    : 'Rejoignez l\'index et boostez votre visibilité IA.'
                  }
                </p>
                <span className={`text-sm font-bold flex items-center gap-1 group-hover:underline ${
                  isAtLimit ? 'text-purple-400' : 'text-purple-400'
                }`}>
                    {isAtLimit ? 'Upgrader mon plan' : 'Ajouter mon site'} <ArrowRight size={14} />
                </span>
            </div>

            {filteredDirectory.map((item) => (
                <div key={item.id} className="ninja-card p-6 rounded-2xl border border-white/[0.08] group hover:border-primary/30 transition-all hover:-translate-y-1 flex flex-col">
                    <div className="flex justify-between items-start mb-4">
                        <div className="flex items-center gap-3">
                            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-gray-800 to-black border border-white/[0.08] flex items-center justify-center text-white font-bold font-sans text-xl shadow-inner">
                                {item.name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-bold text-white flex items-center gap-1">
                                    {item.name} 
                                    {item.verified && <Check size={14} className="text-purple-400" />}
                                </h3>
                                <p className="text-xs text-gray-500">{item.sector}</p>
                            </div>
                        </div>
                        <div className="flex flex-col items-end">
                            <div className={`text-lg font-bold ${item.aeoScore >= 90 ? 'text-purple-300' : 'text-purple-400'}`}>
                                {item.aeoScore}
                            </div>
                            <div className="text-[10px] text-gray-500 uppercase tracking-wider">AEO Score</div>
                        </div>
                    </div>

                    <p className="text-sm text-gray-500 mb-6 line-clamp-2 h-10">
                        {item.desc}
                    </p>

                    <div className="flex items-center justify-between pt-4 border-t border-white/[0.06] mt-auto">
                        <span className={`text-xs px-2 py-1 rounded border ${
                            item.status === 'Elite' ? 'bg-purple-500/10 border-purple-500/30 text-purple-400' :
                            item.status === 'Premium' ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' :
                            'bg-gray-500/10 border-gray-500/30 text-gray-500'
                        }`}>
                            {item.status} Member
                        </span>
                        <button 
                            onClick={() => handleViewDetails(item)}
                            className="text-xs text-white hover:text-purple-400 flex items-center gap-1 transition-colors"
                        >
                            Voir la fiche <ArrowRight size={12} />
                        </button>
                    </div>
                </div>
            ))}
        </div>
    </div>
  );

  // --- COMPOSANT : TUNNEL D'INSCRIPTION (Conservé mais inactif via l'UI actuelle) ---
  const renderJoinFunnel = () => (
    <>
      <div className="mb-8">
        <button onClick={() => setViewMode('browse')} className="flex items-center text-sm text-gray-500 hover:text-white mb-4 transition-colors">
            <ArrowLeft size={16} className="mr-2" /> Retour à l'annuaire
        </button>
        <h2 className="text-3xl font-sans font-bold text-white mb-2">Rejoindre CitedBy Index</h2>
        <div className="flex items-center gap-2">
            <div className={`h-1 w-8 rounded-full ${step === 'intro' ? 'bg-primary' : 'bg-gray-700'}`}></div>
            <div className={`h-1 w-8 rounded-full ${step === 'form' ? 'bg-primary' : 'bg-gray-700'}`}></div>
            <div className={`h-1 w-8 rounded-full ${step === 'payment' ? 'bg-primary' : 'bg-gray-700'}`}></div>
        </div>
      </div>
      {/* ... Content of join funnel kept for potential future use ... */}
      <div className="text-center py-20 text-gray-500">
          Redirection vers la page Plan en cours...
      </div>
    </>
  );

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-[80vh]">

      {viewMode === 'browse' ? (
          <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
            <ArrowLeft size={18} className="mr-2" /> Retour
          </button>
      ) : null}

      {/* VIEW SWITCHING LOGIC */}
      {viewMode === 'browse' ? renderBrowser() : renderJoinFunnel()}

      {/* --- ALERTE LIMITE ATTEINTE --- */}
      {showLimitAlert && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={() => setShowLimitAlert(false)} />
          <div className="relative bg-[#111111] border border-red-500/20 rounded-2xl w-full max-w-md shadow-2xl shadow-red-500/5 overflow-hidden">
            <div className="bg-gradient-to-r from-red-500/10 to-orange-500/10 border-b border-white/[0.06] p-6 text-center">
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-red-500/10 border border-red-500/20 flex items-center justify-center">
                <AlertCircle size={32} className="text-red-400" />
              </div>
              <h2 className="text-xl font-bold text-white mb-2">Limite de projets atteinte</h2>
              <p className="text-sm text-gray-400">
                Votre plan <span className="font-bold text-white">{planLabel}</span> autorise <span className="font-bold text-white">{maxClients}</span> projet{maxClients > 1 ? 's' : ''} maximum.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div className="flex items-center justify-between p-3 bg-white/[0.03] rounded-xl border border-white/[0.06]">
                <span className="text-sm text-gray-400">Projets utilisés</span>
                <span className="text-lg font-bold text-red-400">{directClientCount}/{maxClients}</span>
              </div>
              <p className="text-xs text-gray-500 text-center">
                Passez à un plan supérieur pour ajouter votre entreprise à l'annuaire et créer de nouveaux projets.
              </p>
              <div className="flex gap-3">
                <button
                  onClick={() => setShowLimitAlert(false)}
                  className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors"
                >
                  Fermer
                </button>
                <button
                  onClick={() => {
                    setShowLimitAlert(false);
                    onNavigateToPlan();
                  }}
                  className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-colors shadow-lg shadow-purple-500/20"
                >
                  <Zap size={16} /> Upgrader
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Directory;
